mapper.select:
SELECT r.id, r.user_id, r.metric_type, r.metric_value, r.unit, r.record_date, r.created_at, r.updated_at FROM body_metric_record r INNER JOIN ( SELECT record_date, MAX(id) AS max_id FROM body_metric_record WHERE user_id = #{userId} AND metric_type = #{metricType} GROUP BY record_date ) daily ON daily.max_id = r.id
WHERE ( r.record_date < #{cursorDate} OR (r.record_date = #{cursorDate} AND r.id < #{cursorId}) )
ORDER BY r.record_date DESC, r.id DESC LIMIT #{limit}

SELECT id, user_id, metric_type, metric_value, unit, record_date, created_at, updated_at FROM body_metric_record WHERE user_id = #{userId} AND metric_type = #{metricType}
AND ( record_date < #{cursorDate} OR (record_date = #{cursorDate} AND id < #{cursorId}) )
ORDER BY record_date DESC, id DESC LIMIT #{limit}
